import base64
import numpy as np
from typing import Any, Dict

class Task:
    """Base class for all tasks."""
    pass

def register_task(name: str):
    """Decorator used by the framework to register a task."""
    def decorator(cls):
        return cls
    return decorator

@register_task("base64_encoding")
class Base64Encoding(Task):
    """Base64Encoding Task: encode random binary data using standard Base64."""
    DEFAULT_PLAINTEXT_MULTIPLIER = 2048  # bytes of plaintext per unit of n

    def generate_problem(self, n: int, random_seed: int = 1) -> Dict[str, Any]:
        """Generate random binary data for the task."""
        size = max(0, n * self.DEFAULT_PLAINTEXT_MULTIPLIER)
        if size == 0:
            return {"plaintext": b""}
        rng = np.random.default_rng(random_seed)
        return {"plaintext": rng.bytes(size)}

    def solve(self, problem: Dict[str, Any]) -> Dict[str, bytes]:
        """Encode the plaintext using Base64."""
        encode = base64.b64encode
        return {"encoded_data": encode(problem["plaintext"])}

    def is_solution(self, problem: Dict[str, Any], solution: Dict[str, bytes]) -> bool:
        """Verify that the provided solution matches the reference encoding."""
        if not isinstance(solution, dict) or "encoded_data" not in solution:
            return False
        encode = base64.b64encode
        return solution["encoded_data"] == encode(problem["plaintext"])

def run_solver(problem: Dict[str, Any]) -> Dict[str, bytes]:
    """Convenience wrapper used by the framework."""
    return Base64Encoding().solve(problem)

